import { useCallback } from 'react';
import { useSelector } from 'react-redux';
import { useShallow } from 'zustand/shallow';
import { useRootStore } from '~/store';
import { PermissionStatus } from '../models';
import {
  checkHasRedeemed as checkHasRedeemedService,
  markAsRedeemed as markAsRedeemedService,
} from '../services';

export function usePermission() {
  const accountId = useSelector((state: any) => state?.customerReducer?.nrc);

  const { hasRedeemed, status } = useRootStore(
    useShallow(state => state.rewardsPermission),
  );

  const isLoading = status === PermissionStatus.LOADING;
  const isError = status === PermissionStatus.ERROR;

  const checkHasRedeemed = useCallback(
    async ({
      forceRefresh = false,
    }: { forceRefresh?: boolean } = {}): Promise<boolean> => {
      if (hasRedeemed !== null && !forceRefresh) {
        return hasRedeemed;
      }

      if (!accountId) {
        throw new Error('Expected accountId to be defined.');
      }

      return checkHasRedeemedService(accountId);
    },
    [
      accountId,
      hasRedeemed,
    ],
  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    return markAsRedeemedService(accountId);
  }, [accountId]);

  return {
    hasRedeemed,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

import { StateCreator } from 'zustand';

import {
  AirlineMilesSlice,
  createAirlineMilesSlice,
  createMarketplaceSlice,
  createParameterPointsProgramSlice,
  createPermissionSlice,
  createPointsExtractSlice,
  createPointsProductsSlice,
  createRescueSlice,
  MarketplaceSlice,
  ParameterPointsProgramSlice,
  PermissionSlice,
  PointsExtractSlice,
  PointsProductsSlice,
  RescueSlice,
} from '../index';

export type RewardsProgramRootStore = ParameterPointsProgramSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice &
  PointsProductsSlice &
  RescueSlice &
  MarketplaceSlice;

type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
  slice as Slice<T>;

export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
  ...a: Parameters<Slice<T>>
) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
      ...a,
    ),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
  };
}

